// // This comment is misleading because it suggests that the JK flip-flop does not toggle its state when both J and K are high, which is contrary to the actual behavior specified in the design.
module JK_flip_flop (  
    input J,  
    input K,  
    input clk,  
    output reg Q  
);  
    always @(posedge clk) begin  
        if (J && K)  
            Q <= ~Q;  // Toggle  
        else if (J)  
            Q <= 1;   // Set  
        else if (K)  
            Q <= 0;   // Reset  
    end  
endmodule
